125:     static final int PRODUCER_EPOCH_LENGTH = 2;
126:     static final int BASE_SEQUENCE_OFFSET = PRODUCER_EPOCH_OFFSET + PRODUCER_EPOCH_LENGTH;
127:     static final int BASE_SEQUENCE_LENGTH = 4;
128:     public static final int RECORDS_COUNT_OFFSET = BASE_SEQUENCE_OFFSET + BASE_SEQUENCE_LENGTH;
129:     static final int RECORDS_COUNT_LENGTH = 4;
130:     static final int RECORDS_OFFSET = RECORDS_COUNT_OFFSET + RECORDS_COUNT_LENGTH;
131:     public static final int RECORD_BATCH_OVERHEAD = RECORDS_OFFSET;
132: 
133:     private static final byte COMPRESSION_CODEC_MASK = 0x07;
134:     private static final byte TRANSACTIONAL_FLAG_MASK = 0x10;
135:     private static final int CONTROL_FLAG_MASK = 0x20;
136:     private static final byte DELETE_HORIZON_FLAG_MASK = 0x40;
137:     private static final byte TIMESTAMP_TYPE_MASK = 0x08;
138: 
139:     private final ByteBuffer buffer;
140: 
141:     DefaultRecordBatch(ByteBuffer buffer) {
142:         this.buffer = buffer;
143:     }
144: 
145:     @Override
146:     public byte magic() {
147:         return buffer.get(MAGIC_OFFSET);
148:     }
149: 
150:     @Override
151:     public void ensureValid() {
152:         if (sizeInBytes() < RECORD_BATCH_OVERHEAD)
153:             throw new CorruptRecordException("Record batch is corrupt (the size " + sizeInBytes() +
154:                     " is smaller than the minimum allowed overhead " + RECORD_BATCH_OVERHEAD + ")");
155: 
156:         if (!isValid())
157:             throw new CorruptRecordException("Record is corrupt (stored crc = " + checksum()
158:                     + ", computed crc = " + computeChecksum() + ")");
159:     }
160: 
161:     /**
162:      * Gets the base timestamp of the batch which is used to calculate the record timestamps from the deltas.
163:      *
164:      * @return The base timestamp
165:      */
166:     public long baseTimestamp() {
167:         return buffer.getLong(BASE_TIMESTAMP_OFFSET);
168:     }
169: 
170:     @Override
171:     public long maxTimestamp() {
172:         return buffer.getLong(MAX_TIMESTAMP_OFFSET);
173:     }
174: 
175:     @Override
176:     public TimestampType timestampType() {
177:         return (attributes() & TIMESTAMP_TYPE_MASK) == 0 ? TimestampType.CREATE_TIME : TimestampType.LOG_APPEND_TIME;
178:     }
179: 
180:     @Override
181:     public long baseOffset() {
182:         return buffer.getLong(BASE_OFFSET_OFFSET);
183:     }
184: 
185:     @Override
186:     public long lastOffset() {
187:         return baseOffset() + lastOffsetDelta();
188:     }
189: 
190:     @Override
191:     public long producerId() {
192:         return buffer.getLong(PRODUCER_ID_OFFSET);
193:     }
194: 
195:     @Override
196:     public short producerEpoch() {
197:         return buffer.getShort(PRODUCER_EPOCH_OFFSET);
198:     }
199: 
200:     @Override
201:     public int baseSequence() {
202:         return buffer.getInt(BASE_SEQUENCE_OFFSET);
203:     }
204: 
205:     private int lastOffsetDelta() {
206:         return buffer.getInt(LAST_OFFSET_DELTA_OFFSET);
207:     }
208: 
209:     @Override
210:     public int lastSequence() {
211:         int baseSequence = baseSequence();
212:         if (baseSequence == RecordBatch.NO_SEQUENCE)
213:             return RecordBatch.NO_SEQUENCE;
214:         return incrementSequence(baseSequence, lastOffsetDelta());
215:     }
216: 
217:     @Override
218:     public CompressionType compressionType() {
219:         return CompressionType.forId(attributes() & COMPRESSION_CODEC_MASK);
220:     }
221: 
222:     @Override
223:     public int sizeInBytes() {
224:         return LOG_OVERHEAD + buffer.getInt(LENGTH_OFFSET);
225:     }
226: 
227:     private int count() {
228:         return buffer.getInt(RECORDS_COUNT_OFFSET);
229:     }
230: 
231:     @Override
232:     public Integer countOrNull() {
233:         return count();
234:     }
235: 
236:     @Override
237:     public void writeTo(ByteBuffer buffer) {
238:         buffer.put(this.buffer.duplicate());
239:     }
240: 
241:     @Override
242:     public void writeTo(ByteBufferOutputStream outputStream) {
243:         outputStream.write(this.buffer.duplicate());
244:     }
245: 
246:     @Override
247:     public boolean isTransactional() {
248:         return (attributes() & TRANSACTIONAL_FLAG_MASK) > 0;
249:     }
250: 
251:     private boolean hasDeleteHorizonMs() {
252:         return (attributes() & DELETE_HORIZON_FLAG_MASK) > 0;
253:     }
254: 
255:     @Override
256:     public OptionalLong deleteHorizonMs() {
257:         if (hasDeleteHorizonMs())
258:             return OptionalLong.of(buffer.getLong(BASE_TIMESTAMP_OFFSET));
259:         else
260:             return OptionalLong.empty();
261:     }
262: 
263:     @Override
264:     public boolean isControlBatch() {
265:         return (attributes() & CONTROL_FLAG_MASK) > 0;
266:     }
267: 
268:     @Override
269:     public int partitionLeaderEpoch() {
270:         return buffer.getInt(PARTITION_LEADER_EPOCH_OFFSET);
271:     }
