366:     @Override
367:     public void setLastOffset(long offset) {
368:         buffer.putLong(BASE_OFFSET_OFFSET, offset - lastOffsetDelta());
369:     }
370: 
371:     @Override
372:     public void setMaxTimestamp(TimestampType timestampType, long maxTimestamp) {
373:         long currentMaxTimestamp = maxTimestamp();
374:         // We don't need to recompute crc if the timestamp is not updated.
375:         if (timestampType() == timestampType && currentMaxTimestamp == maxTimestamp)
376:             return;
377: 
378:         byte attributes = computeAttributes(compressionType(), timestampType, isTransactional(), isControlBatch(), hasDeleteHorizonMs());
379:         buffer.putShort(ATTRIBUTES_OFFSET, attributes);
380:         buffer.putLong(MAX_TIMESTAMP_OFFSET, maxTimestamp);
381:         long crc = computeChecksum();
382:         ByteUtils.writeUnsignedInt(buffer, CRC_OFFSET, crc);
383:     }
384: 
385:     @Override
386:     public void setPartitionLeaderEpoch(int epoch) {
387:         buffer.putInt(PARTITION_LEADER_EPOCH_OFFSET, epoch);
388:     }
389: 
390:     @Override
391:     public long checksum() {
392:         return ByteUtils.readUnsignedInt(buffer, CRC_OFFSET);
393:     }
394: 
395:     public boolean isValid() {
396:         return sizeInBytes() >= RECORD_BATCH_OVERHEAD && checksum() == computeChecksum();
397:     }
398: 
399:     private long computeChecksum() {
400:         return Crc32C.compute(buffer, ATTRIBUTES_OFFSET, buffer.limit() - ATTRIBUTES_OFFSET);
401:     }
402: 
403:     private byte attributes() {
404:         // note we're not using the second byte of attributes
405:         return (byte) buffer.getShort(ATTRIBUTES_OFFSET);
406:     }
