505:                 "sequence=[" + baseSequence() + ", " + lastSequence() + "], " +
506:                 "partitionLeaderEpoch=" + partitionLeaderEpoch() + ", " +
507:                 "isTransactional=" + isTransactional() + ", isControlBatch=" + isControlBatch() + ", " +
508:                 "compression=" + compressionType() + ", timestampType=" + timestampType() + ", crc=" + checksum() + ")";
509:     }
