549:     /**
550:      * Get an upper bound on the size of a batch with only a single record using a given key and value. This
551:      * is only an estimate because it does not take into account additional overhead from the compression
552:      * algorithm used.
553:      */
554:     static int estimateBatchSizeUpperBound(ByteBuffer key, ByteBuffer value, Header[] headers) {
555:         return RECORD_BATCH_OVERHEAD + DefaultRecord.recordSizeUpperBound(key, value, headers);
556:     }
