570:     // visible for testing
571:     abstract class RecordIterator implements CloseableIterator<Record> {
572:         private final Long logAppendTime;
573:         private final long baseOffset;
574:         private final long baseTimestamp;
575:         private final int baseSequence;
576:         private final int numRecords;
577:         private int readRecords = 0;
578: 
579:         RecordIterator() {
580:             this.logAppendTime = timestampType() == TimestampType.LOG_APPEND_TIME ? maxTimestamp() : null;
581:             this.baseOffset = baseOffset();
582:             this.baseTimestamp = baseTimestamp();
583:             this.baseSequence = baseSequence();
584:             int numRecords = count();
585:             if (numRecords < 0)
586:                 throw new InvalidRecordException("Found invalid record count " + numRecords + " in magic v" +
587:                         magic() + " batch");
588:             this.numRecords = numRecords;
589:         }
590: 
591:         @Override
592:         public boolean hasNext() {
593:             return readRecords < numRecords;
594:         }
595: 
596:         @Override
597:         public Record next() {
598:             if (readRecords >= numRecords)
599:                 throw new NoSuchElementException();
600: 
601:             readRecords++;
602:             Record rec = readNext(baseOffset, baseTimestamp, baseSequence, logAppendTime);
603:             if (readRecords == numRecords) {
604:                 // Validate that the actual size of the batch is equal to declared size
605:                 // by checking that after reading declared number of items, there no items left
606:                 // (overflow case, i.e. reading past buffer end is checked elsewhere).
607:                 if (!ensureNoneRemaining())
608:                     throw new InvalidRecordException("Incorrect declared batch size, records still remaining in file");
609:             }
610:             return rec;
611:         }
612: 
613:         protected abstract Record readNext(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime);
614: 
615:         protected abstract boolean ensureNoneRemaining();
616: 
617:         @Override
618:         public void remove() {
619:             throw new UnsupportedOperationException();
620:         }
621: 
622:     }
