397:     public static class FilterResult {
398:         private ByteBuffer outputBuffer;
399:         private int messagesRead = 0;
400:         // Note that `bytesRead` should contain only bytes from batches that have been processed, i.e. bytes from
401:         // `messagesRead` and any discarded batches.
402:         private int bytesRead = 0;
403:         private int messagesRetained = 0;
404:         private int bytesRetained = 0;
405:         private long maxOffset = -1L;
406:         private long maxTimestamp = RecordBatch.NO_TIMESTAMP;
