/**
 * A record batch is a container for records. In old versions of the record format (versions 0 and 1),
 * a batch consisted always of a single record if no compression was enabled, but could contain
 * many records otherwise. Newer versions (magic versions 2 and above) will generally contain many records
 * regardless of compression.
 *
 * <p><strong>Thread-safety:</strong> RecordBatch implementations are <strong>not thread-safe</strong>.
 * Batches backed by ByteBuffer are particularly vulnerable to concurrent modification. Multiple threads
 * should not access the same batch concurrently. However, different batches can be safely accessed by
 * different threads in parallel.
 *
 * <p><strong>Usage:</strong> Record batches are typically accessed through {@link MemoryRecords} or
 * {@link Records} implementations, which manage the underlying buffer lifecycle. Direct instantiation
 * of batch implementations is uncommon in normal usage.
 */
public interface RecordBatch extends Iterable<Record> {

    /**
     * The "magic" values
     */
    byte MAGIC_VALUE_V0 = 0;
    byte MAGIC_VALUE_V1 = 1;
    byte MAGIC_VALUE_V2 = 2;

